        initLogic() {
            const vehicleListContainer = this.shadowRoot.getElementById('vehicleList');
            const transportData = [
                { plate: 'DW 8472A', driver: 'Adam Nowak', eta: 'T-02 MIN', status: 'ARRIVING', isAlert: true },
                { plate: 'PO 1293B', driver: 'Piotr Wisniewski', eta: 'T-14 MIN', status: 'IN_TRANSIT', isAlert: false },
                { plate: 'WZ 0092X', driver: 'Kamil Wojcik', eta: 'T-21 MIN', status: 'IN_TRANSIT', isAlert: false },
                { plate: 'KR 5532Y', driver: 'Michal Kowalski', eta: 'T-45 MIN', status: 'DELAYED', isAlert: false }
            ];

            transportData.forEach(item => {
                const vNode = document.createElement('div');
                vNode.className = `vehicle-item ${item.isAlert ? 'alert' : ''}`;
                vNode.innerHTML = `
                    <div class="v-plate">${item.plate}</div>
                    <div class="v-driver">${item.driver}</div>
                    <div class="v-eta">${item.eta}</div>
                    <div class="v-status">${item.status}</div>
                `;
                vNode.addEventListener('click', () => {
                    console.log(`[OXY_OS] LOG: Selected vehicle ${item.plate}`);
                });
                vehicleListContainer.appendChild(vNode);
            });

            // Efekt skanera terminala (subtelne miganie)
            setInterval(() => {
                const listItems = this.shadowRoot.querySelectorAll('.vehicle-item');
                listItems.forEach(item => {
                    item.style.opacity = '0.7';
                    setTimeout(() => item.style.opacity = '1', 150);
                });
            }, 8000);
        }
    }

    // 2. Rejestracja Web Componentu
    if (!customElements.get('oxy-parking-radar')) {
        customElements.define('oxy-parking-radar', OxyParkingRadar);
    }

    // 3. Wstrzyknięcie panelu na stronę po załadowaniu Slacka
    window.addEventListener('load', () => {
        setTimeout(() => {
            const radar = document.createElement('oxy-parking-radar');
            document.body.appendChild(radar);
            console.log('[OXY_OS] Radar Injected to host DOM.');
        }, 2000); // Małe opóźnienie, by Slack zdążył się wyrenderować
    });

})();
